function processResults(questions, responses) {
    return questions.map((question)=>{
        const answers = responses.map((r)=>r.answers[question.id]).filter((a)=>a !== undefined && a !== null && a !== '');
        const result = {
            questionId: question.id,
            questionText: question.question_text,
            questionType: question.question_type,
            responseCount: answers.length,
            data: {}
        };
        switch(question.question_type){
            case 'single_choice':
            case 'multiple_choice':
                {
                    const options = question.options || [];
                    const counts = {};
                    options.forEach((opt)=>{
                        counts[opt.id] = 0;
                    });
                    answers.forEach((answer)=>{
                        if (Array.isArray(answer)) {
                            answer.forEach((id)=>{
                                if (counts[id] !== undefined) counts[id]++;
                            });
                        } else if (typeof answer === 'string' && counts[answer] !== undefined) {
                            counts[answer]++;
                        }
                    });
                    result.data = {
                        type: 'bar',
                        options: options.map((opt)=>({
                                label: opt.text,
                                value: counts[opt.id] || 0,
                                percentage: answers.length > 0 ? Math.round(counts[opt.id] / answers.length * 100) : 0
                            }))
                    };
                    break;
                }
            case 'scale':
            case 'rating':
            case 'number':
                {
                    const numbers = answers.filter((a)=>typeof a === 'number');
                    const sum = numbers.reduce((acc, n)=>acc + n, 0);
                    const avg = numbers.length > 0 ? sum / numbers.length : 0;
                    const min = numbers.length > 0 ? Math.min(...numbers) : 0;
                    const max = numbers.length > 0 ? Math.max(...numbers) : 0;
                    result.data = {
                        type: 'stats',
                        average: Math.round(avg * 10) / 10,
                        min,
                        max,
                        distribution: calculateDistribution(numbers, question.question_type)
                    };
                    break;
                }
            case 'text':
            case 'long_text':
                {
                    result.data = {
                        type: 'text',
                        responses: answers.slice(0, 20) // Show first 20 responses
                    };
                    break;
                }
            case 'date':
                {
                    result.data = {
                        type: 'text',
                        responses: answers.slice(0, 20)
                    };
                    break;
                }
            default:
                result.data = {
                    type: 'text',
                    responses: answers.slice(0, 20)
                };
        }
        return result;
    });
}
function calculateDistribution(numbers, type) {
    if (numbers.length === 0) return [];
    const counts = {};
    const maxValue = type === 'rating' ? 5 : 10;
    for(let i = 1; i <= maxValue; i++){
        counts[i] = 0;
    }
    numbers.forEach((n)=>{
        if (counts[n] !== undefined) counts[n]++;
    });
    return Object.entries(counts).map(([value, count])=>({
            value: parseInt(value),
            count
        }));
}
